import { Client, ClientConfiguration } from '@openfga/sdk';
import { FGA_MODEL } from './fga-model';

export class FgaService {
  private client: Client;

  constructor(config: ClientConfiguration) {
    this.client = new Client(config);
  }

  async setup() {
    await this.client.writeAuthorizationModel({
      authorization_model: FGA_MODEL,
    });
  }

  async writeTuple(user: string, relation: string, object: string) {
    await this.client.write({
      writes: [{ user, relation, object }],
    });
  }

  async check(user: string, relation: string, object: string): Promise<boolean> {
    const { allowed } = await this.client.check({ user, relation, object });
    return allowed;
  }

  async batchCheckViewers(user: string, documentIds: string[]): Promise<string[]> {
    // In a real production env, we use batchCheck to avoid N+1 queries
    const checks = documentIds.map(id => 
      this.client.check({ user, relation: 'viewer', object: `document:${id}` })
    );
    const results = await Promise.all(checks);
    return documentIds.filter((_, i) => results[i].allowed);
  }
}
```

